import React from 'react';
import { Block } from './Block';
import './index.scss';

function App() {
  const [fromCurrency, setFromCurrency] =  React.useState('RUB');
  const [toCurrency, setToCurrency] =  React.useState('USD');
  const [fromPrice, setFromPrice] =  React.useState(0);
  const [toPrice, setToPrice] =  React.useState(1);
  const retesRef = React.useRef({})

  React.useEffect(() => {
    fetch("https://v6.exchangerate-api.com/v6/4f9f861f549296e372c9a74d/latest/USD")
    .then((res) => res.json())
    .then((json) => {
      retesRef.current = json.rates;
      onChangeToPrice(1);
    }).catch(err => {
      console.warn(err);
      alert('Не удалось получить данные');
    })
  }, []);

  const onChangeFromPrice = (value) => {
    const price = value / retesRef.current[fromCurrency];
    const result = price * retesRef.current[toCurrency];
    setToPrice(result);
    setFromPrice(value);
  }

  const onChangeToPrice = (value) => {
    const result = (retesRef.current[fromCurrency] / retesRef.current[toCurrency] * value);
    setFromPrice(result);
    setToPrice(value);
  }

  React.useEffect(() =>{
    onChangeFromPrice(fromPrice);
  }, [fromCurrency]);

  React.useEffect(() =>{
    onChangeToPrice(toPrice);
  }, [toCurrency]);

  return (
    <div className="App">
      <Block value={fromPrice} currency={fromCurrency} 
      onChangeCurrency={setFromCurrency} 
      onChangeValue={onChangeFromPrice}
      />
      <Block value={toPrice} currency={toCurrency} 
      onChangeCurrency={setToCurrency} 
      onChangeValue={onChangeToPrice}
      />
    </div>
  );
}

export default App;
